export default function createTtlStorage(storage, now = () => Date.now()) {
  if (!storage || typeof storage.getItem !== 'function') {
    throw new TypeError('storage must implement getItem/setItem/removeItem');
  }

  const set = (key, value, ttlMs) => {
    const exp = ttlMs == null ? null : now() + Math.max(0, ttlMs);
    const payload = JSON.stringify({ v: value, exp });
    storage.setItem(String(key), payload);
  };

  const get = (key) => {
    const raw = storage.getItem(String(key));
    if (raw == null) return null;
    try {
      const data = JSON.parse(raw);
      if (!data || !('v' in data)) return null;
      if (data.exp != null && now() >= data.exp) {
        storage.removeItem(String(key));
        return null;
      }
      return data.v;
    } catch {
      storage.removeItem(String(key));
      return null;
    }
  };

  const remove = (key) => {
    storage.removeItem(String(key));
  };

  return { set, get, remove };
}
